const {
  ComponentContext,
  PropsContext: ChartPropsContext,
  useComponentContext: useChartComponentContext,
  usePropsContext: useChartPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<ChartProps, ChartStyle, ComponentContext>(
  "chart",
